import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onSuccess, onClose }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({ 
    title: '', location: '', startDate: '', endDate: '', 
    description: '', importantNotes: '', capacity: '', 
    price: '', discount: '', status: 'Available'
  });

  useEffect(() => {
    if (editingTour) {
      const formattedData = { ...editingTour };
      if (editingTour.startDate) formattedData.startDate = editingTour.startDate.split('T')[0];
      if (editingTour.endDate) formattedData.endDate = editingTour.endDate.split('T')[0];
      setFormData(formattedData);
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const config = { headers: { Authorization: `Bearer ${user.token}` } };
      // 關鍵：過濾掉系統欄位，否則後端會報錯
      const { _id, __v, createdAt, updatedAt, ...payload } = formData;

      if (editingTour) {
        await axiosInstance.put(`/api/tours/${editingTour._id}`, payload, config);
      } else {
        await axiosInstance.post('/api/tours', payload, config);
      }
      alert('Success!');
      onSuccess();
    } catch (error) {
      alert('Save failed: ' + (error.response?.data?.message || 'Check Server'));
    }
  };

  // 🔴 修正後的刪除邏輯
  const handleDelete = async () => {
    if (!editingTour?._id) return;
    if (!window.confirm("Are you sure you want to delete this package?")) return;

    try {
      await axiosInstance.delete(`/api/tours/${editingTour._id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      alert('Deleted Successfully!');
      onSuccess(); // 這會觸發 Tours.jsx 的重新抓取並關閉視窗
    } catch (error) {
      console.error(error);
      const errorMsg = error.response?.data?.message || 'Delete failed. Check console.';
      alert(errorMsg);
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-white">
      {/* Header */}
      <div className="flex justify-between items-center p-5 border-b sticky top-0 bg-white z-10">
        <button type="button" onClick={onClose} className="text-2xl text-gray-400">←</button>
        <h1 className="text-lg font-black text-gray-800">{editingTour ? 'Edit Details' : 'Add Tour Package'}</h1>
        <button type="button" onClick={onClose} className="text-2xl text-gray-400">🏠</button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6 flex-1 overflow-y-auto pb-32">
        {/* 設計稿欄位：Title, Location, Date, Description... */}
        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Tour Title</label>
          <input type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl outline-none" required />
        </div>

        {/* ... (其他欄位保持與之前一致) ... */}

        <div>
          <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Important Notes</label>
          <textarea rows="3" value={formData.importantNotes} onChange={e => setFormData({...formData, importantNotes: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl outline-none" placeholder="Enter Important Notes" />
        </div>

        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Price (AUD)</label>
            <input type="number" value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl" required />
          </div>
          <div className="flex-1">
            <label className="block text-xs font-bold text-gray-400 mb-2 uppercase">Status</label>
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl appearance-none">
              <option value="Available">Available</option>
              <option value="Unavailable">Unavailable</option>
            </select>
          </div>
        </div>

        <button type="submit" className="w-full bg-emerald-500 text-white font-bold py-5 rounded-[24px] shadow-lg shadow-emerald-100 mt-4 active:scale-95 transition">
          {editingTour ? 'Update Changes' : 'Submit'}
        </button>

        {/* 🔴 刪除按鈕 */}
        {editingTour && (
          <button 
            type="button" 
            onClick={handleDelete}
            className="w-full text-red-500 font-bold py-2 mt-2 hover:bg-red-50 rounded-xl transition"
          >
            Delete Tour Package
          </button>
        )}
      </form>
    </div>
  );
};

export default TourForm;
